mapper.select:
SELECT p.*, u.username, u.avatar as user_avatar
FROM posts p
JOIN users u ON p.user_id = u.id
WHERE p.user_id = #{userId}
ORDER BY p.created_at DESC
LIMIT #{page}, #{size}

SELECT p.*, u.username, u.avatar as user_avatar
FROM posts p
JOIN users u ON p.user_id = u.id
WHERE p.user_id = #{userId} AND p.status = #{status}
ORDER BY p.created_at DESC
LIMIT #{page}, #{size}

SELECT p.*, u.username, u.avatar as user_avatar
FROM posts p
JOIN users u ON p.user_id = u.id
WHERE FIND_IN_SET(#{tag}, p.tags) > 0 AND p.status = #{status}
ORDER BY p.created_at DESC
LIMIT #{page}, #{size}

